/* REGARDING THE HOLY DAYS — self-contained album */
var HOLY_DAYS = [{"id":"the-holy-days","num":1,"title":"The Holy Days","type":"wtlb","sourceLabel":"Words To Live By: Part Two","paragraphs":[{"align":"center","text":"The significance of The Holy Days is found\n\nIn their meaning and revealed by their order..."},{"align":"center","text":"Even as all find their fulfillment in The Messiah\n\nAnd their completion in the coming of The Lord..."},{"align":"center","text":"Says The Lord."}],"nextEntry":{"id":"embracing-the-gift","title":"Embracing The Gift"},"scriptures":{}},{"id":"embracing-the-gift","num":2,"title":"Embracing The Gift","type":"wtlb","sourceLabel":"Words To Live By: Part One","paragraphs":[{"align":"center","text":"The Holy Days are the\n\nStepping stones to Heaven..."},{"align":"center","text":"In understanding their meaning shall you\n\nProgress quickly along the path I have laid..."},{"align":"center","text":"And when I have fulfilled them to the last\n\nThe journey shall be complete,\n\nFor those who have accepted and received...\n\n\n\nSays The Lord YahuShua."}],"prevEntry":{"id":"the-holy-days","title":"The Holy Days"},"nextEntry":{"id":"the-salvation-day","title":"The Salvation Day"},"scriptures":{}},{"id":"the-salvation-day","num":3,"title":"The Salvation Day","type":"wtlb","sourceLabel":"Words To Live By: Part One","paragraphs":[{"align":"center","text":"The Salvation Day of Men is four-fold:"},{"align":"center","text":"It was ordained before the foundation\n\nOf the world, fulfilled at My birth,\n\nFinished at My death on the cross,\n\nAnd solidified eternally upon My resurrection...\n\n\n\nSays The Lord YahuShua."}],"prevEntry":{"id":"embracing-the-gift","title":"Embracing The Gift"},"nextEntry":{"id":"consider-my-love","title":"Consider My Love"},"scriptures":{}},{"id":"consider-my-love","num":4,"title":"Consider My Love","type":"wtlb","sourceLabel":"Words To Live By: Part One","paragraphs":[{"align":"center","text":"Behold My hands and My feet, and consider My love;\n\nFor the scars of My passion remain,\n\nA holy, everlasting covenant\n\nWritten in the blood of The Lamb."},{"align":"center","text":"Taste and see, beloved, drink!\n\nUntil that which is veiled is veiled no longer,\n\nUntil the void within your heart is filled."},{"align":"center","text":"For My love was written in every stripe I endured for you,\n\nPoured out in every drop of blood I shed for you,\n\nRevealed when you pierced My hands and My feet."},{"align":"center","text":"Beloved, I am married unto you!..."},{"align":"center","text":"A union sealed forever in the blood we share...\n\n\n\nSays The Lord YahuShua."}],"prevEntry":{"id":"the-salvation-day","title":"The Salvation Day"},"nextEntry":{"id":"walking-in-the-footsteps-of-the-messiahs-passion","title":"Walking in the Footsteps of The Messiah’s Passion"},"scriptures":{}},{"id":"walking-in-the-footsteps-of-the-messiahs-passion","num":5,"title":"Walking in the Footsteps of The Messiah’s Passion","type":"letter","sourceLabel":"Volume Four","date":"2/10/10","from":"From The Lord, Our God and Savior","spoken":"The Word of The Lord Spoken to Timothy","forLine":"For The Lord’s Little Flock, and For All Those Who Have Ears to Hear","blocks":[{"type":"para","segments":[{"t":"bold-italic","v":"Thus says The Lord to those who believe, to those who have ears to hear, eyes to see, and a heart which longs to know Me as I truly am:"},{"t":"text","v":"Three are fulfilled, one is, and three are to come, coming quickly. Of the three fulfilled, you shall remember and honor them according to how I command you. The dates and times, the new moons and seasons, are not the focus; rather, YahuShua is the focus. For the significance of these Holy Days is found in their meaning and revealed by their order, even as all find their fulfillment in The Messiah and their completion in the coming of The Lord. Thus you shall not keep My Holy Days as the world, nor as those held captive in the churches of men, nor shall you follow the futile traditions of the Jews. For those who deny The Son deny The Father also; their worship is in vain. For the Jews reject The Son of Salvation, and the churches of men pollute His name and corrupt His image without ceasing. For they do always follow the dictates of their own hearts, and in their stubbornness they hold fast to religion, embracing the commandments of men, walking in every perverse doctrine and tradition thereof, which I hate! Therefore you shall set yourselves apart from them, and do all I command you: You shall honor the Passover a week before the time, beginning Tuesday at sundown. You shall walk in the footsteps of Messiah, and remember, blessing His name and giving thanks according to each day He fulfilled in His Passion. Four holy convocations, plus one, shall be kept."}]},{"type":"poetry","lines":[[{"t":"italic","v":"As The Messiah kept The Passover,"}],[{"t":"italic","v":"So shall you in like manner keep The Passover..."}]]},{"type":"poetry","lines":[[{"t":"italic","v":"As He was afflicted, you shall fast..."}]]},{"type":"poetry","lines":[[{"t":"italic","v":"As He slept in the tomb, you shall mourn..."}]]},{"type":"poetry","lines":[[{"t":"italic","v":"And as He rose from the grave,"}],[{"t":"italic","v":"You shall rejoice and sing praises..."}]]},{"type":"poetry","lines":[[{"t":"italic","v":"Behold, you shall complete the week with joy and feasting..."}]]},{"type":"poetry","lines":[[{"t":"italic","v":"Then later shall you remember The Bridegroom being taken from you,"}],[{"t":"italic","v":"And rejoice in the Blessed Hope of His soon return."}]]},{"type":"para","segments":[{"t":"text","v":"In this way will you begin to partake of the hidden manna, and your hearts shall be glad, causing you to see with greater eyes; your understanding of the Glory brightening as you enter into a more profound knowledge of the salvation of God, which is accomplished and fulfilled in The Son of Man. For the Holy Days are revelation, revealing hidden things kept secret since the world began - signposts of things to come, a foretaste of The Kingdom, a glimpse into the Glory of God even as the Scriptures, unfolding and coming to light as the will of God is manifest."}]},{"type":"para","segments":[{"t":"text","v":"And though you are counted as last partakers by the Jews, and scorned by those who dwell in the churches of men, I tell you, you shall be first partakers. For I have set you apart as an example, and by these things shall you bear witness of My comings and goings. For I am The Lord, and I shall surely follow the counsel of My own will. For I do not receive counsel from men, nor shall I follow the line which they have stretched out for Me, that I might adhere to their rules or meet their expectations; rather I do that which is right and good in My own eyes. Therefore those who diligently seek to know The Father must abide in The Son, and obey His voice - living testaments to those without knowledge, an ensign to all nations, soon taken up, first partakers of the Glory."}]},{"type":"poetry","lines":[[{"t":"italic","v":"Indeed, many who are counted as first will be last,"}],[{"t":"italic","v":"And many who are counted as last shall be first..."}]]},{"type":"poetry","lines":[[{"t":"italic","v":"For those mocked and persecuted"}],[{"t":"italic","v":"For My name’s sake must be first..."}]]},{"type":"poetry","lines":[[{"t":"italic","v":"Even as those who are mocked and persecuted"}],[{"t":"italic","v":"Because of this Word shall be first also..."}]]},{"type":"poetry","lines":[[{"t":"italic","v":"I AM THE LORD."}]]}],"footnotes":{},"nkjv":{},"audioUrl":"https://thevolumesoftruth.bandcamp.com/track/walking-in-the-footsteps-of-the-messiahs-passion","videoVoiceUrl":"https://www.youtube.com/watch?v=4McEeRHG1wc&list=PLE8FlkxQPQkMkjV_V68yjBNVY-LTyD5Xy&index=20","videoMusicUrl":"https://www.youtube.com/user/trumpetcallofgod","relatedTopics":[{"label":"Regarding The Holy Days of God","url":"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"},{"label":"The Coming of The Lord","url":"https://answersonlygodcangive.com/The_Coming_of_The_Lord#The_Coming_of_The_Lord"},{"label":"The Messiah","url":"https://answersonlygodcangive.com/The_Messiah"}],"prevEntry":{"id":"consider-my-love","title":"Consider My Love"},"nextEntry":{"id":"do-this-in-remembrance-of-me","title":"Do This in Remembrance of Me"}},{"id":"do-this-in-remembrance-of-me","num":6,"title":"Do This in Remembrance of Me","type":"letter","sourceLabel":"Volume Two","date":"4/25/05","from":"From YahuShua HaMashiach, Our Lord and Savior","spoken":"The Word of The Lord Spoken to Timothy","forLine":"For Timothy, and For All Those Who Have Ears to Hear","blocks":[{"type":"para","segments":[{"t":"bold-italic","v":"Listen and have understanding, for thus says The Lord your Redeemer:"},{"t":"text","v":"Only those who truly believe keep the Passover. To them it is a memorial, a time of reflection and the giving of thanks, a Sabbath."}]},{"type":"para","segments":[{"t":"text","v":"Therefore, Timothy, do not your own pleasure on the Holy Days or on the Sabbath."},{"t":"fn","v":"1"},{"t":"text","v":"Rather do that which pleases The Lord your God. Keep the feasts holy, and cause your life to follow suit; unleaven your heart. Discern what is most needful, and when in doubt, ask. And concerning the rites and ceremonial symbols of the feasts, consider their meaning and rejoice in their fulfillment, for it is accomplished. Do not agonize over the details, nor stumble over the letter. And concerning that which you partake of for the body, it is of little consequence. Rather feast upon that which sustains your soul. Remember Me and My Passion, as I have shown you; offer up thanksgiving, and consider your salvation and The Loving Mercy of God. For the intent of one’s heart speaks volumes more than the offering put forth by their hands. Yet I tell you the truth, many will there be who enter The Kingdom of Heaven, who did not keep the feasts of The Lord. And many will there be left standing outside the gates, who kept the feasts of The Lord. For those without the gate retain their sin, for they hold fast to malice and have not yet departed from wickedness."},{"t":"fn","v":"2"},{"t":"text","v":"Yet the hearts of the first election are filled with compassion and a sincere desire to walk in My ways, having called upon My name in sincerity and in truth, as they bring forth new works meet for repentance."},{"t":"fn","v":"3"},{"t":"text","v":"For where there are righteous works, there are also those who seek to spoil them for the sake of pride and envy. And where there is pure knowledge, there are also those who defile it among women."},{"t":"fn","v":"4"},{"t":"text","v":"Take heed, therefore, and remember My teaching:"},{"t":"italic","v":"Beware of the leaven of the Pharisees and the Sadducees."},{"t":"fn","v":"5"},{"t":"text","v":"For their like still exists today; only their names and vesture have changed."}]},{"type":"poetry","lines":[[{"t":"italic","v":"Yet the ignorance of the meek is no cause for offense,"}],[{"t":"italic","v":"Nor shall the error of the humble bring forth rebuke;"}],[{"t":"italic","v":"For I know the heart and look upon the innermost intentions"},{"t":"fn","v":"6"},{"t":"italic","v":"..."}]]},{"type":"poetry","lines":[[{"t":"italic","v":"Therefore keep the feast, not with the old leaven,"}],[{"t":"italic","v":"Nor with the leaven of malice and wickedness,"}],[{"t":"italic","v":"But with the unleavened bread of sincerity and truth,"}],[{"t":"italic","v":"As it is written in accordance with the New Covenant"},{"t":"fn","v":"7"},{"t":"italic","v":"..."}]]},{"type":"closing","text":"Says The Lord."}],"footnotes":{"1":{"type":"scripture","ref":"Isaiah 58:13"},"2":{"type":"scripture","ref":"Revelation 22:15"},"3":{"type":"scripture","ref":"Matthew 3:8"},"4":{"type":"note","text":"“Women” in this context refers to the churches of men"},"5":{"type":"scripture","ref":"Matthew 16:6"},"6":{"type":"scripture","ref":"Jeremiah 17:10"},"7":{"type":"scripture","ref":"1 Corinthians 5:7-8"}},"nkjv":{"Isaiah 58:13":"“If you turn away your foot from the Sabbath, From doing your pleasure on My holy day, And call the Sabbath a delight, The holy day of the LORD honorable, And shall honor Him, not doing your own ways, Nor finding your own pleasure, Nor speaking your own words,","Revelation 22:15":"But outside are dogs and sorcerers and sexually immoral and murderers and idolaters, and whoever loves and practices a lie.","Matthew 3:8":"Therefore bear fruits worthy of repentance,","Matthew 16:6":"Then Jesus said to them, “Take heed and beware of the leaven of the Pharisees and the Sadducees.”","Jeremiah 17:10":"I, the LORD, search the heart, I test the mind, Even to give every man according to his ways, According to the fruit of his doings.","1 Corinthians 5:7-8":"7. Therefore purge out the old leaven, that you may be a new lump, since you truly are unleavened. For indeed Christ, our Passover, was sacrificed for us. 8. Therefore let us keep the feast, not with old leaven, nor with the leaven of malice and wickedness, but with the unleavened bread of sincerity and truth."},"audioUrl":"https://thevolumesoftruth.bandcamp.com/track/do-this-in-remembrance-of-me","soundcloudUrl":"https://soundcloud.com/the-volumes-of-truth/do-this-in-remembrance-of-me?in=the-volumes-of-truth/sets/volume-two","videoVoiceUrl":"https://www.youtube.com/watch?v=_k7yeHHdvYc&list=PLE8FlkxQPQkM99Siv2xPqHtuLS9gEQ6FA&index=7","videoMusicUrl":"https://www.youtube.com/user/trumpetcallofgod","relatedTopics":[{"label":"Regarding The Holy Days of God","url":"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"},{"label":"God Speaks About The Sabbath","url":"https://answersonlygodcangive.com/God_Speaks_About_The_Sabbath"},{"label":"The Messiah","url":"https://answersonlygodcangive.com/The_Messiah"},{"label":"Regarding The Kingdom and Heaven","url":"https://answersonlygodcangive.com/Regarding_The_Kingdom_and_Heaven"}],"prevEntry":{"id":"walking-in-the-footsteps-of-the-messiahs-passion","title":"Walking in the Footsteps of The Messiah’s Passion"},"nextEntry":{"id":"i-am-the-passover-and-the-lamb-the-new-covenant-with-men","title":"I Am The Passover and The Lamb, The New Covenant with Men"}},{"id":"i-am-the-passover-and-the-lamb-the-new-covenant-with-men","num":7,"title":"I Am The Passover and The Lamb, The New Covenant with Men","type":"letter","sourceLabel":"Volume Two","date":"4/18/05","from":"From YahuShua HaMashiach, Our Lord and Savior","spoken":"The Word of The Lord Spoken to Timothy","forLine":"For All Those Who Have Ears to Hear","blocks":[{"type":"para","segments":[{"t":"bold-italic","v":"Thus says The Messiah who is called Christ, The Holy One of Israel:"},{"t":"text","v":"I am The Lamb of God without spot or blemish, the blood which was shed and placed upon the doorposts,"},{"t":"fn","v":"1"},{"t":"text","v":"delivering My people from the power of sin,"},{"t":"fn","v":"2"},{"t":"text","v":"which is death."},{"t":"fn","v":"3"},{"t":"text","v":"I am The Passover."},{"t":"fn","v":"4"},{"t":"text","v":"For as it is written in The Law, all things must be purified with blood, and without the shedding of blood there can be no remission."},{"t":"fn","v":"5"},{"t":"text","v":"Thus no one goes to The Father, unless they receive of Me. Unless they eat My flesh and drink My blood, they have no life in them. For whosoever eats My flesh and drinks My blood has everlasting life, and I will raise them up at the Last Day. For My flesh is food indeed, and My blood is drink indeed. Thus all who eat My flesh and drink My blood live in Me, and I in them. I am The Living Bread which came down from Heaven! If anyone eats this bread, he will live forever! And the bread that I gave was My flesh, which was given for the life of the world. This I have already told you."},{"t":"fn","v":"6"},{"t":"text","v":"Therefore keep the Passover in remembrance of Me and My Passion, according to The New Covenant."},{"t":"fn","v":"7"},{"t":"text","v":"For it is accomplished, and was sealed forevermore upon My resurrection. For The Lamb was slain, My people redeemed in all the earth; and behold, I am risen, crowned with glory and honor, forever and ever."},{"t":"fn","v":"8"},{"t":"text","v":"Amen."}]},{"type":"para","segments":[{"t":"text","v":"Therefore, again I say to you, celebrate Passover, yet not as in the days of Moses; nor as the unbelieving in Israel, upon whom the veil remains, for they have yet to look upon Me."},{"t":"fn","v":"9"},{"t":"text","v":"For the Passover was a signpost, a shadow of glorious things to come."},{"t":"fn","v":"10"},{"t":"text","v":"Read the writing thereof and have understanding, take its meaning to heart."},{"t":"fn","v":"11"},{"t":"text","v":"For the Holy Days are revelation, the Plan of the Ages revealed."}]},{"type":"poetry","lines":[[{"t":"italic","v":"Therefore rejoice, My people, for your Redeemer lives!"}],[{"t":"italic","v":"Death has passed over you!..."}]]},{"type":"poetry","lines":[[{"t":"italic","v":"Therefore eat, drink, and give thanks"}],[{"t":"italic","v":"In remembrance of Me, and I shall also"}],[{"t":"italic","v":"Remember you in the day I gather My own..."}]]},{"type":"poetry","lines":[[{"t":"italic","v":"Then shall you truly know Me,"}],[{"t":"italic","v":"Just as I have always known you,"}],[{"t":"italic","v":"Even from the foundation of the world..."}]]},{"type":"closing-fn","segments":[{"t":"italic","v":"Says He who is, and was, and is to come,"},{"t":"fn","v":"12"},{"t":"italic","v":"YahuShua, The Salvation of God."}]}],"footnotes":{"1":{"type":"scripture","ref":"Exodus 12:1-27"},"2":{"type":"scripture","ref":"John 1:29"},"3":{"type":"scripture","ref":"Romans 6:23"},"4":{"type":"scripture","ref":"1 Corinthians 5:7"},"5":{"type":"scripture","ref":"Hebrews 9:22"},"6":{"type":"scripture","ref":"John 6:48-58"},"7":{"type":"scripture","ref":"Luke 22:14-20"},"8":{"type":"scripture","ref":"Hebrews 2:9"},"9":{"type":"scripture","ref":"Zechariah 12:10"},"10":{"type":"scripture","ref":"Colossians 2:16-17"},"11":{"type":"scripture","ref":"Hebrews 10:1-19"},"12":{"type":"scripture","ref":"Revelation 1:4, Revelation 1:8, Revelation 11:17"}},"nkjv":{"Exodus 12:1-27":"1. Now the LORD spoke to Moses and Aaron in the land of Egypt, saying, 2. “This month shall be your beginning of months; it shall be the first month of the year to you. 3. Speak to all the congregation of Israel, saying: ‘On the tenth of this month every man shall take for himself a lamb, according to the house of his father, a lamb for a household. 4. And if the household is too small for the lamb, let him and his neighbor next to his house take it according to the number of the persons; according to each man’s need you shall make your count for the lamb. 5. Your lamb shall be without blemish, a male of the first year. You may take it from the sheep or from the goats. 6. Now you shall keep it until the fourteenth day of the same month. Then the whole assembly of the congregation of Israel shall kill it at twilight. 7. And they shall take some of the blood and put it on the two doorposts and on the lintel of the houses where they eat it. 8. Then they shall eat the flesh on that night; roasted in fire, with unleavened bread and with bitter herbs they shall eat it. 9. Do not eat it raw, nor boiled at all with water, but roasted in fire—its head with its legs and its entrails. 10. You shall let none of it remain until morning, and what remains of it until morning you shall burn with fire. 11. And thus you shall eat it: with a belt on your waist, your sandals on your feet, and your staff in your hand. So you shall eat it in haste. It is the LORD’s Passover. 12. ‘For I will pass through the land of Egypt on that night, and will strike all the firstborn in the land of Egypt, both man and beast; and against all the gods of Egypt I will execute judgment: I am the LORD. 13. Now the blood shall be a sign for you on the houses where you are. And when I see the blood, I will pass over you; and the plague shall not be on you to destroy you when I strike the land of Egypt. 14. ‘So this day shall be to you a memorial; and you shall keep it as a feast to the LORD throughout your generations. You shall keep it as a feast by an everlasting ordinance. 15. Seven days you shall eat unleavened bread. On the first day you shall remove leaven from your houses. For whoever eats leavened bread from the first day until the seventh day, that person shall be cut off from Israel. 16. On the first day there shall be a holy convocation, and on the seventh day there shall be a holy convocation for you. No manner of work shall be done on them; but that which everyone must eat—that only may be prepared by you. 17. So you shall observe the Feast of Unleavened Bread, for on this same day I will have brought your armies out of the land of Egypt. Therefore you shall observe this day throughout your generations as an everlasting ordinance. 18. In the first month, on the fourteenth day of the month at evening, you shall eat unleavened bread, until the twenty-first day of the month at evening. 19. For seven days no leaven shall be found in your houses, since whoever eats what is leavened, that same person shall be cut off from the congregation of Israel, whether he is a stranger or a native of the land. 20. You shall eat nothing leavened; in all your dwellings you shall eat unleavened bread.’ ” 21. Then Moses called for all the elders of Israel and said to them, “Pick out and take lambs for yourselves according to your families, and kill the Passover lamb. 22. And you shall take a bunch of hyssop, dip it in the blood that is in the basin, and strike the lintel and the two doorposts with the blood that is in the basin. And none of you shall go out of the door of his house until morning. 23. For the LORD will pass through to strike the Egyptians; and when He sees the blood on the lintel and on the two doorposts, the LORD will pass over the door and not allow the destroyer to come into your houses to strike you. 24. And you shall observe this thing as an ordinance for you and your sons forever. 25. It will come to pass when you come to the land which the LORD will give you, just as He promised, that you shall keep this service. 26. And it shall be, when your children say to you, ‘What do you mean by this service?’ 27. that you shall say, ‘It is the Passover sacrifice of the LORD, who passed over the houses of the children of Israel in Egypt when He struck the Egyptians and delivered our households.’ ” So the people bowed their heads and worshiped.","John 1:29":"The next day John saw Jesus coming toward him, and said, “Behold! The Lamb of God who takes away the sin of the world!","Romans 6:23":"For the wages of sin is death, but the gift of God is eternal life in Christ Jesus our Lord.","1 Corinthians 5:7":"Therefore purge out the old leaven, that you may be a new lump, since you truly are unleavened. For indeed Christ, our Passover, was sacrificed for us.","Hebrews 9:22":"And according to the law almost all things are purified with blood, and without shedding of blood there is no remission.","John 6:48-58":"48. I am the bread of life. 49. Your fathers ate the manna in the wilderness, and are dead. 50. This is the bread which comes down from heaven, that one may eat of it and not die. 51. I am the living bread which came down from heaven. If anyone eats of this bread, he will live forever; and the bread that I shall give is My flesh, which I shall give for the life of the world.” 52. The Jews therefore quarreled among themselves, saying, “How can this Man give us His flesh to eat?” 53. Then Jesus said to them, “Most assuredly, I say to you, unless you eat the flesh of the Son of Man and drink His blood, you have no life in you. 54. Whoever eats My flesh and drinks My blood has eternal life, and I will raise him up at the last day. 55. For My flesh is food indeed, and My blood is drink indeed. 56. He who eats My flesh and drinks My blood abides in Me, and I in him. 57. As the living Father sent Me, and I live because of the Father, so he who feeds on Me will live because of Me. 58. This is the bread which came down from heaven—not as your fathers ate the manna, and are dead. He who eats this bread will live forever.”","Luke 22:14-20":"14. When the hour had come, He sat down, and the twelve apostles with Him. 15. Then He said to them, “With fervent desire I have desired to eat this Passover with you before I suffer; 16. for I say to you, I will no longer eat of it until it is fulfilled in the kingdom of God.” 17. Then He took the cup, and gave thanks, and said, “Take this and divide it among yourselves; 18. for I say to you, I will not drink of the fruit of the vine until the kingdom of God comes.” 19. And He took bread, gave thanks and broke it, and gave it to them, saying, “This is My body which is given for you; do this in remembrance of Me.” 20. Likewise He also took the cup after supper, saying, “This cup is the new covenant in My blood, which is shed for you.","Hebrews 2:9":"But we see Jesus, who was made a little lower than the angels, for the suffering of death crowned with glory and honor, that He, by the grace of God, might taste death for everyone.","Zechariah 12:10":"“And I will pour on the house of David and on the inhabitants of Jerusalem the Spirit of grace and supplication; then they will look on Me whom they pierced. Yes, they will mourn for Him as one mourns for his only son, and grieve for Him as one grieves for a firstborn.","Colossians 2:16-17":"16. So let no one judge you in food or in drink, or regarding a festival or a new moon or sabbaths, 17. which are a shadow of things to come, but the substance is of Christ.","Hebrews 10:1-19":"1. For the law, having a shadow of the good things to come, and not the very image of the things, can never with these same sacrifices, which they offer continually year by year, make those who approach perfect. 2. For then would they not have ceased to be offered? For the worshipers, once purified, would have had no more consciousness of sins. 3. But in those sacrifices there is a reminder of sins every year. 4. For it is not possible that the blood of bulls and goats could take away sins. 5. Therefore, when He came into the world, He said: “Sacrifice and offering You did not desire, But a body You have prepared for Me. 6. In burnt offerings and sacrifices for sin You had no pleasure. 7. Then I said, ‘Behold, I have come— In the volume of the book it is written of Me— To do Your will, O God.’ ” 8. Previously saying, “Sacrifice and offering, burnt offerings, and offerings for sin You did not desire, nor had pleasure in them” (which are offered according to the law), 9. then He said, “Behold, I have come to do Your will, O God.” He takes away the first that He may establish the second. 10. By that will we have been sanctified through the offering of the body of Jesus Christ once for all. 11. And every priest stands ministering daily and offering repeatedly the same sacrifices, which can never take away sins. 12. But this Man, after He had offered one sacrifice for sins forever, sat down at the right hand of God, 13. from that time waiting till His enemies are made His footstool. 14. For by one offering He has perfected forever those who are being sanctified. 15. But the Holy Spirit also witnesses to us; for after He had said before, 16. “This is the covenant that I will make with them after those days, says the LORD: I will put My laws into their hearts, and in their minds I will write them,” 17. then He adds, “Their sins and their lawless deeds I will remember no more.” 18. Now where there is remission of these, there is no longer an offering for sin. 19. Therefore, brethren, having boldness to enter the Holiest by the blood of Jesus,","Revelation 1:4, Revelation 1:8, Revelation 11:17":"Revelation 1:4 — John, to the seven churches which are in Asia: Grace to you and peace from Him who is and who was and who is to come, and from the seven Spirits who are before His throne, | Revelation 1:8 — “I am the Alpha and the Omega, the Beginning and the End,” says the Lord, “who is and who was and who is to come, the Almighty.” | Revelation 11:17 — saying: “We give You thanks, O Lord God Almighty, The One who is and who was and who is to come, Because You have taken Your great power and reigned."},"audioUrl":"https://thevolumesoftruth.bandcamp.com/track/i-am-the-passover-and-the-lamb-the-new-covenant-with-men-2","soundcloudUrl":"https://soundcloud.com/the-volumes-of-truth/i-am-the-passover-and-the-lamb?in=the-volumes-of-truth/sets/volume-two","videoVoiceUrl":"https://www.youtube.com/watch?v=SQNOSo5XNLw&list=PLE8FlkxQPQkM99Siv2xPqHtuLS9gEQ6FA&index=4","videoMusicUrl":"https://www.youtube.com/watch?v=IB6TJi3Q92Y&list=PLSVchFJ22QYLFnEgsgioj_Lej_q1CzyfH&index=18","relatedTopics":[{"label":"Regarding The Holy Days of God","url":"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"},{"label":"The Messiah","url":"https://answersonlygodcangive.com/The_Messiah"},{"label":"Regarding The Crucifixion","url":"https://answersonlygodcangive.com/Regarding_The_Crucifixion"},{"label":"Regarding the First and Second Resurrection","url":"https://answersonlygodcangive.com/Regarding_the_First_and_Second_Resurrection"},{"label":"Regarding Salvation","url":"https://answersonlygodcangive.com/Regarding_Salvation"}],"prevEntry":{"id":"do-this-in-remembrance-of-me","title":"Do This in Remembrance of Me"},"nextEntry":{"id":"keep-the-passover","title":"Keep The Passover"}},{"id":"keep-the-passover","num":8,"title":"Keep The Passover","type":"letter","sourceLabel":"Volume Three","date":"3/20/07","from":"From YahuShua HaMashiach, Our Lord and Savior","spoken":"The Word of The Lord Spoken to Timothy","forLine":"For All Those Who Have Ears to Hear","blocks":[{"type":"para","segments":[{"t":"bold-italic","v":"Thus says The Lord:"},{"t":"text","v":"My children, keep the Passover. Keep it according to the New Covenant, in faith and love, and remember. Yet you who call of yourselves Christian do always dishonor Me. Behold, you pollute the glory of My sacrifice with filthy traditions and desecrate My resurrection with pagan practices, forsaking those things which you were to keep holy and remember, nor will you incline the ear. Churches of men, know you not that in these Seven (the Holy Days) is wisdom and understanding, the very mind of God?! Yet you choose vanities on top of vanities, embracing corrupt doctrine and pagan-laced tradition, placing your stamp of approval on them. For you are a most perverse and adulterous generation. Churches of men, I am not of this world, yet you are of this world. Thus only those who obey My voice trust in Me, and only those who embrace Me as I truly am are set apart. For I live in them and they follow Me. You claim you trust in Me and that I live in you, yet not one of you obeys My voice; indeed, you ignore My example and refuse to walk in My ways. For if I truly lived in you, then you would do as I did. Beloved, follow Me! Keep the Passover, honor the Holy Days, and remember the Sabbath. Only then will you begin to see, only then will you understand. For the Holy Days are revelation, every Sabbath a blessing, a sign between Me and you that you may know I am The Lord who sanctifies you."}]},{"type":"poetry","lines":[[{"t":"italic","v":"And behold, four are fulfilled:"}],[{"t":"italic","v":"Salvation assured, sin and death overcome, the Spirit given..."}]]},{"type":"poetry","lines":[[{"t":"italic","v":"Three are coming quickly:"}],[{"t":"italic","v":"Sin destroyed, evil bound, My seat taken, Judgment..."}]]},{"type":"poetry","lines":[[{"t":"italic","v":"A new day, even one thousand years..."}]]},{"type":"poetry","lines":[[{"t":"italic","v":"Then a short season, consummation..."}]]},{"type":"poetry","lines":[[{"t":"italic","v":"An everlasting day in The Lord!..."}]]},{"type":"poetry","lines":[[{"t":"italic","v":"Amen, and amen."}]]}],"footnotes":{},"nkjv":{},"audioUrl":"https://thevolumesoftruth.bandcamp.com/track/keep-the-passover-2","soundcloudUrl":"https://soundcloud.com/the-volumes-of-truth/keep-the-passover?in=the-volumes-of-truth/sets/volume-three","videoVoiceUrl":"https://www.youtube.com/watch?v=UHSdSNJvX58&list=PLE8FlkxQPQkOki3y3XQqS8Nx49EwLuRld&index=38","videoMusicUrl":"https://www.youtube.com/user/trumpetcallofgod","relatedTopics":[{"label":"Regarding The Holy Days of God","url":"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"},{"label":"The Messiah","url":"https://answersonlygodcangive.com/The_Messiah"},{"label":"Regarding the Holidays of Men","url":"https://answersonlygodcangive.com/Regarding_the_Holidays_of_Men"},{"label":"God Speaks About Idolatry","url":"https://answersonlygodcangive.com/God_Speaks_About_Idolatry"},{"label":"God Speaks Regarding Those Who Take His Name in Vain","url":"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain"},{"label":"Regarding the Churches of Men","url":"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{"label":"Regarding Obedience","url":"https://answersonlygodcangive.com/Regarding_Obedience"},{"label":"God Speaks About The Sabbath","url":"https://answersonlygodcangive.com/God_Speaks_About_The_Sabbath"},{"label":"Regarding Salvation","url":"https://answersonlygodcangive.com/Regarding_Salvation"},{"label":"Regarding The Kingdom and Heaven","url":"https://answersonlygodcangive.com/Regarding_The_Kingdom_and_Heaven"}],"prevEntry":{"id":"i-am-the-passover-and-the-lamb-the-new-covenant-with-men","title":"I Am The Passover and The Lamb, The New Covenant with Men"},"nextEntry":{"id":"unleavened","title":"Unleavened"}},{"id":"unleavened","num":9,"title":"Unleavened","type":"letter","sourceLabel":"Volume Three","date":"4/19/06","from":"From The Lord, Our God and Savior","spoken":"The Word of The Lord Spoken to Timothy","forLine":"For All Those Who Have Ears to Hear","blocks":[{"type":"para","segments":[{"t":"bold-italic","v":"Thus says The Lord, The Risen One, your Redeemer:"},{"t":"text","v":"I had come to you as a man, clothed in the flesh, humble; My glory set aside, God become man, Immanu El... Living as all have lived in the body, yet not as man lives in the spirit; for I am clean, having no sin in My body, nor in My spirit, having obeyed every command of The Father - blameless."}]},{"type":"para","segments":[{"t":"bold-italic","v":"Thus says The Lord God:"},{"t":"text","v":"Behold The Lamb of God without spot or blemish, sent to die for the sins of the world, bearing the full weight of transgression in His own body; the perfect sacrifice, acceptable to God, whereby all men are reconciled to The Father if they so choose to receive of The Free Gift, becoming once again My sons and daughters, free to enter the Garden and My love, from which they shall never again depart."}]},{"type":"para","segments":[{"t":"bold-italic","v":"Thus says The Risen Lamb:"},{"t":"text","v":"Therefore, as I have unleavened all men by My sacrifice, in the same way must those who live in Me crucify their lives daily, bearing their cross after Me. For the first six days of the feast shall be for a physical representation of My command to you:"},{"t":"italic","v":"You are forgiven, now go out and sin no more."},{"t":"text","v":"Be then separate from the ways of this world and the churches of men, and be for Me a strange and peculiar people who remain in My love, even as I kept The Father’s commands and remain in His love. And the seventh day, it is the consummation of the six gone before, a holy convocation, the cleansing completed, a rest from all works against temptation and the many snares of the evil one. For I am coming quickly, and I shall make a complete end of all iniquity, of all things which lead My people into sin. For I had come at the first to unleaven all men, to heal the hearts of all who receive of Me, to bring peace to the minds of all who believe in Me, to set the captives free - I am The Passover! And now I am returning to make a complete end of all leaven which fills this world; behold, in a week and in the Day shall I accomplish it. Then rest, peace, one thousand years. So then, My children, even all who gather together in My name, have understanding of the Plan of the Ages. In the sixth day, the leaven of sin entered the Garden; and on the seventh, God rested, and blessed the seventh day and sanctified it. Thus here is wisdom:"},{"t":"italic","v":"Six days, creation; the seventh, rest, holy. Six days since Adam; the seventh, rest, holy. Six days shall you labor; the seventh, rest, holy. Six days shall you feast; the seventh, rest, holy."}]},{"type":"poetry","lines":[[{"t":"italic","v":"Therefore, eat and drink in remembrance of Me;"}],[{"t":"italic","v":"Be filled with the glory of The Lord!"}],[{"t":"italic","v":"For I died; behold, I am risen!..."}]]},{"type":"closing","text":"Says The Amen, The Firstborn from the dead, YahuShua HaMashiach, Lord and Savior of men."}],"footnotes":{},"nkjv":{},"audioUrl":"https://thevolumesoftruth.bandcamp.com/track/unleavened","soundcloudUrl":"https://soundcloud.com/the-volumes-of-truth/unleavened?in=the-volumes-of-truth/sets/volume-three","videoVoiceUrl":"https://www.youtube.com/watch?v=z2pjy0bgeYI&list=PLE8FlkxQPQkOki3y3XQqS8Nx49EwLuRld&index=21","videoMusicUrl":"https://www.youtube.com/user/trumpetcallofgod","relatedTopics":[{"label":"Regarding The Holy Days of God","url":"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"},{"label":"The Messiah","url":"https://answersonlygodcangive.com/The_Messiah"},{"label":"Regarding The Crucifixion","url":"https://answersonlygodcangive.com/Regarding_The_Crucifixion"},{"label":"Regarding Salvation","url":"https://answersonlygodcangive.com/Regarding_Salvation"},{"label":"Regarding the Day of The Lord","url":"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{"label":"The Coming of The Lord","url":"https://answersonlygodcangive.com/The_Coming_of_The_Lord"},{"label":"Regarding the Day and Hour Unknown","url":"https://answersonlygodcangive.com/Regarding_the_Day_and_Hour_Unknown"},{"label":"God Speaks About The Sabbath","url":"https://answersonlygodcangive.com/God_Speaks_About_The_Sabbath"},{"label":"Regarding The Kingdom and Heaven","url":"https://answersonlygodcangive.com/Regarding_The_Kingdom_and_Heaven"}],"prevEntry":{"id":"keep-the-passover","title":"Keep The Passover"},"nextEntry":{"id":"devotion","title":"Devotion"}},{"id":"devotion","num":10,"title":"Devotion","type":"letter","sourceLabel":"Letters to The Lord's Little Flock","date":"3/7/10","from":"From The Lord, Our God and Savior","spoken":"The Word of The Lord Spoken to Timothy","forLine":"For The Lord’s Little Flock, and For All Those Who Have Ears to Hear","blocks":[{"type":"para","segments":[{"t":"bold-italic","v":"Thus says The Lord to His servants:"},{"t":"text","v":"You shall partake only of that which is molded by the hands of a believing bride in each household, doing so with love and great joy in remembrance of Me. For I am He who molded you, and yet molds you still, even as I had unleavened you from the beginning by My sacrifice, remembering you during My Passion. Therefore, take and eat of that which I have provided. Do not go roundabout, nor seek that which is created by the hands of men; accept no replacements. Rather trust in My ways and see with greater eyes, rejoicing in every act of devotion, for I AM HE. Yet for those of you who have no wife, or dwell with a spouse who remains unwilling, you shall prepare the bread with your own hands, and be set apart for these seven days of the feast."}]},{"type":"para","segments":[{"t":"text","v":"Thus concerning spouses who remain rebellious, I say this: Ask of them nothing, nor partake of anything they offer during My Holy Days. For they have shown themselves unworthy of Me. For though you are two of one flesh by marriage, a division in spirit has occurred. And as it is written:"},{"t":"italic","v":"Whatever you bind on earth will be bound in Heaven, and whatever you loose on earth will be loosed in Heaven."},{"t":"fn","v":"1"},{"t":"text","v":"Thus in the same way, when a division occurs on earth because of Me, so also is there a division in Heaven, says The Lord."}]},{"type":"poetry","lines":[[{"t":"italic","v":"For My bride cleaves to Me, she honors Me"}],[{"t":"italic","v":"And walks in My ways, and remains faithful..."}]]},{"type":"poetry","lines":[[{"t":"italic","v":"Yet any who claim to be My bride, who knowingly"}],[{"t":"italic","v":"Commit adultery with the pagan and the heathen,"}],[{"t":"italic","v":"While cleaving to the ways of this world"}],[{"t":"italic","v":"Or the churches of men, dishonor Me..."}]]},{"type":"poetry","lines":[[{"t":"italic","v":"Thus between us a great gulf has formed..."}]]},{"type":"poetry","lines":[[{"t":"italic","v":"And so shall it remain, until the day comes"}],[{"t":"italic","v":"And is fulfilled, when she cries out, saying,"}],[{"t":"italic","v":"“Blessed is He who comes in The Name of The Lord!”"}]]}],"footnotes":{"1":{"type":"scripture","ref":"Matthew 18:18"}},"nkjv":{"Matthew 18:18":"“Assuredly, I say to you, whatever you bind on earth will be bound in heaven, and whatever you loose on earth will be loosed in heaven."},"audioUrl":"https://thevolumesoftruth.bandcamp.com/track/devotion","videoVoiceUrl":"https://www.youtube.com/watch?v=nQjhhK4Yg6A&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=20","videoMusicUrl":"https://www.youtube.com/user/trumpetcallofgod","relatedTopics":[{"label":"Regarding The Holy Days of God","url":"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"},{"label":"Regarding the True Bride","url":"https://answersonlygodcangive.com/Regarding_The_True_Church#Section_2_-_The_True_Bride"}],"prevEntry":{"id":"unleavened","title":"Unleavened"},"nextEntry":{"id":"i-am-risen","title":"I AM RISEN"}},{"id":"i-am-risen","num":11,"title":"I AM RISEN","type":"letter","sourceLabel":"Volume Three","date":"4/21/06","from":"From YahuShua HaMashiach, Our Lord and Savior","spoken":"The Word of The Lord Spoken to Timothy","forLine":"For All Those Who Have Ears to Hear","blocks":[{"type":"para","segments":[{"t":"bold-italic","v":"Thus says The Everlasting who would be man, Immanu El:"},{"t":"italic","v":"I was born into the world of the virgin, the chosen vessel by which the salvation of man would come; Growing, Living as all men, yet remaining unspotted from the world, blameless..."}]},{"type":"para","segments":[{"t":"italic","v":"Born to die, suffering as no man could endure, the healing of many in the blood of sprinkling, Death; My spirit committed to The Father, all things accomplished, the cup of The Father consumed..."}]},{"type":"para","segments":[{"t":"italic","v":"The grain of wheat, The Holy Seed, has fallen and died, planted in the heart of the earth for three days and three nights. For I gave My life as a ransom for many, even unto death. I have the power to lay down My life, and behold, I have the power to take it up again."}]},{"type":"poetry","lines":[[{"t":"italic","v":"I AM THE RESURRECTION AND THE LIFE!..."}]]},{"type":"poetry","lines":[[{"t":"italic","v":"And all who believe in Me shall not die, but live,"}],[{"t":"italic","v":"For I shall raise them up at the Last Day!..."}]]},{"type":"poetry","lines":[[{"t":"italic","v":"No more tears, no more death, no more pain,"}],[{"t":"italic","v":"For the old order of things has passed away;"}],[{"t":"italic","v":"All things restored in glory, the glory of everlasting life!..."}]]},{"type":"poetry","lines":[[{"t":"italic","v":"I AM RISEN! YOUR REDEEMER LIVES!..."}]]},{"type":"poetry","lines":[[{"t":"italic","v":"Says The Holy One of Israel."}]]}],"footnotes":{},"nkjv":{},"audioUrl":"https://thevolumesoftruth.bandcamp.com/track/i-am-risen","soundcloudUrl":"https://soundcloud.com/the-volumes-of-truth/i-am-risen?in=the-volumes-of-truth/sets/volume-three","videoVoiceUrl":"https://www.youtube.com/watch?v=na0m8NsQkps&list=PLE8FlkxQPQkOki3y3XQqS8Nx49EwLuRld&index=22","videoMusicUrl":"https://www.youtube.com/watch?v=ZlQABsbo7sc&list=PLSVchFJ22QYLFnEgsgioj_Lej_q1CzyfH&index=21","relatedTopics":[{"label":"Regarding The Holy Days of God","url":"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"},{"label":"The Name of The Lord - \"Immanu El\"","url":"https://answersonlygodcangive.com/The_Name_of_The_Lord#Immanu_El"},{"label":"The Messiah","url":"https://answersonlygodcangive.com/The_Messiah"},{"label":"Regarding The Crucifixion","url":"https://answersonlygodcangive.com/Regarding_The_Crucifixion"},{"label":"Regarding The Resurrection","url":"https://answersonlygodcangive.com/Regarding_The_Resurrection"},{"label":"Regarding Salvation","url":"https://answersonlygodcangive.com/Regarding_Salvation"},{"label":"Regarding The Kingdom and Heaven","url":"https://answersonlygodcangive.com/Regarding_The_Kingdom_and_Heaven"}],"prevEntry":{"id":"devotion","title":"Devotion"},"nextEntry":{"id":"i-shall-remove-my-hand-and-my-spirit-shall-be-withdrawn-and-that-purposed-from-the-beginning-shall-be-done-it-shall-be-accomplished-swiftly","title":"I Shall Remove My Hand and My Spirit Shall Be Withdrawn... And That Purposed from the Beginning Shall Be Done, It Shall Be Accomplished Swiftly"}},{"id":"i-shall-remove-my-hand-and-my-spirit-shall-be-withdrawn-and-that-purposed-from-the-beginning-shall-be-done-it-shall-be-accomplished-swiftly","num":12,"title":"I Shall Remove My Hand and My Spirit Shall Be Withdrawn... And That Purposed from the Beginning Shall Be Done, It Shall Be Accomplished Swiftly","type":"letter","sourceLabel":"Volume Seven","date":"5/19/10","from":"From The Lord, Our God and Savior","spoken":"The Word of The Lord Spoken to Timothy","forLine":"For All Those Who Have Ears to Hear","blocks":[{"type":"para","segments":[{"t":"italic","v":"This question was asked of The Lord, for a sister in Christ: Lord, is this really the last Pentecost?"}]},{"type":"para","segments":[{"t":"italic","v":"[The Lord answered]"},{"t":"text","v":"Beloved, I have poured out My spirit on all flesh, even as I was poured out for you from the beginning. Yet no one comes to drink, not one is willing to receive of Me as I truly am. I have brought forth the rains in their due season, both the former and the latter, and still the crop wanes and bears only bitter fruit. Behold, the voice of The Lord your God has spoken, yet few have ears to hear, few are willing to open their heart and truly listen. I tell you the truth, before Me stands a very proud people, multitudes of foolish children who can not discern their right hand from their left. Their knowledge is corrupt; all their thoughts and musings only serve to uphold their vile nature. For they do not retain God in their thoughts, and from The Holy they are far removed."}]},{"type":"para","segments":[{"t":"bold-italic","v":"Therefore, thus says The Lord:"},{"t":"text","v":"The churches of men are perverse, their ways corrupt, a wholly ignorant and vain people, multitudes of deceived children, a people who were to prepare My way before Me! Yet they have chosen another way, twisting and segregating the Scriptures, both adding to and taking away, that they may continue to uphold their own corrupt doctrines and filthy traditions, which I hate! Therefore, woe to those who dwell in the churches of men! Woe to all who walk in their ways! HYPOCRITES! And of the hypocrite’s portion they shall surely receive, unless they repent and return to Me wholly and in truth! Says The Lord. For I tell you the truth, behold, I declare it to you plainly, if I were to come down and speak in the former manner, every one of these churches of men would bar My way before Me; even every one of them would cast Me out and seek to have Me arrested! Yet I have indeed passed through the midst of them, and though they have not seen Me, as I live, says The Lord, they have surely rejected Me!"}]},{"type":"poetry","lines":[[{"t":"italic","v":"I have poured out My spirit, yet they refuse to drink!"}],[{"t":"italic","v":"I have spoken to them, yet they shut their ears to My voice!"}],[{"t":"italic","v":"I have sent My messengers to them, yet they cast them out"}],[{"t":"italic","v":"With great anger and violence, persecuting and slandering them!..."}]]},{"type":"poetry","lines":[[{"t":"italic","v":"Behold, even the least of these, My servants, have been"}],[{"t":"italic","v":"Mistreated by these so-called people of faith!..."}]]},{"type":"poetry","lines":[[{"t":"italic","v":"THEY HAVE SURELY HATED ME!"}]]},{"type":"para","segments":[{"t":"text","v":"It is written:"},{"t":"italic","v":"The heart of this people has waxed gross, their ears are very dull of hearing and their eyes they have shut, lest at any time they should see with their eyes and hear with their ears and understand with their heart, and be fully converted, and I should heal them."},{"t":"fn","v":"1"},{"t":"text","v":"Yet they have not returned to Me, nor will they repent. How then shall I heal them? For only those who know they are sick seek out The Physician. Yet those who perceive themselves as well will in no wise come to Me. Indeed they remain seated firmly in the darkness of their own understanding, resting upon their laurels by which they highly esteem themselves, as they for a pretense worship another messiah. For one who peers through stained glass can not behold his own image, nor is he able to see those inside clearly. For he sees only an outline, a blur of color obscuring his vision. And those on the inside who peer outward remain blinded, able to perceive only a shadow of what truly is, holding up the hand against the brightness, for fear of the noonday sun which is about to come in."},{"t":"fn","v":"2"},{"t":"text","v":" Thus they prefer the light filtered and the brilliance masked, by means of all this painted glass. What then shall a people such as this do when night has fallen? Thus the churches of men do always take the name of The Lord in vain, by all they say and do. From the least even unto the greatest, they pollute My name, even to the continual blaspheming of the Spirit. Therefore I shall indeed remove My hand, and My spirit shall return to Me. Behold, from every individual who refuses to give heed to My voice and embrace My correction has it departed already. Yet let all those who remain in My love understand and have peace. For though My spirit departs from the multitudes and the ensuing darkness be thick, though wickedness overflows and every man of pride who being wise in his own eyes is left confounded, I shall not make a total end. For My hand shall remain with the faithful, and My strength shall be revealed in My anointed. Behold, My spirit shall well up within the hearts of the penitent and come upon My chosen as a welcomed rain, and they shall be greatly increased, shining ever brighter, even amidst thick clouds and darkness."}]},{"type":"poetry","lines":[[{"t":"italic","v":"Behold The Lord’s purpose, for it shall surely"}],[{"t":"italic","v":"Be accomplished, it shall surely be done:"}]]},{"type":"poetry","lines":[[{"t":"italic","v":"From My left hand, judgment shall be poured out"}],[{"t":"italic","v":"Upon the desolate, the high-minded and the hypocrite..."}]]},{"type":"poetry","lines":[[{"t":"italic","v":"Yet under the shadow of My right hand,"}],[{"t":"italic","v":"The humble shall be hidden..."}]]},{"type":"closing","text":"For I am The Lord, and I do not change."}],"footnotes":{"1":{"type":"scripture","ref":"Matthew 13:15 (KJV)"},"2":{"type":"note","text":"See: \"THE CUP OF THE WRATH OF MY FURY IS COME TO THE FULL\"","url":"https://www.thevolumesoftruth.com/THE_CUP_OF_THE_WRATH_OF_MY_FURY_IS_COME_TO_THE_FULL","link":{"collection":"The Lord's Rebuke","letterTitle":"THE CUP OF THE WRATH OF MY FURY IS COME TO THE FULL"}}},"nkjv":{"Matthew 13:15 (KJV)":"For this people’s heart is waxed gross, and\ntheir ears are dull of hearing, and their eyes they have closed; lest at any time they should see with\ntheir eyes, and hear with\ntheir ears, and should understand with\ntheir\n heart, and should be converted, and I should heal them."},"audioUrl":"https://thevolumesoftruth.bandcamp.com/track/i-shall-remove-my-hand-and-my-spirit-shall-be-withdrawn-and-that-purposed-from-the-beginning-shall-be-done-it-shall-be-accomplished-swiftly","videoVoiceUrl":"https://www.youtube.com/watch?v=PUowi1iW1iA&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=49","videoMusicUrl":"https://www.youtube.com/user/trumpetcallofgod","relatedTopics":[{"label":"Regarding The Holy Days of God","url":"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"},{"label":"Regarding the Churches of Men","url":"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{"label":"*Even More Related Topics","url":"https://answersonlygodcangive.com/index.php?search=%225%2F19%2F10%22&title=Special%3ASearch&go=Go"}],"prevEntry":{"id":"i-am-risen","title":"I AM RISEN"},"nextEntry":{"id":"pentecost","title":"Pentecost"}},{"id":"pentecost","num":13,"title":"Pentecost","type":"letter","sourceLabel":"Volume Six","date":"6/6/11","from":"From YahuShua HaMashiach, Our Lord and Savior","spoken":"The Word of The Lord Spoken to Timothy","forLine":"For The Lord’s Little Flock, and For All Those Who Have Ears to Hear","blocks":[{"type":"para","segments":[{"t":"text","v":"Little flock, hear and understand the will and discipline of The Lord Most High. For I tell you the truth, Pentecost has been fulfilled; behold, it has passed them by unawares. Yet for some it remains, and shall also continue until the time. For many are called, yet few are chosen. Therefore have compassion and pray for them, beloved. For in the same way, you also looked to the time and waited for My words, yet they did not come. And some of you took it upon yourselves to run ahead, impatient, lacking trust, while still others waited patiently; yet all were unaware of My will, save one."}]},{"type":"para","segments":[{"t":"text","v":"Beloved, here is wisdom: The penitent wait and bow down in thanksgiving. Yet the arrogant and false righteous stand up proudly, declaring their deliverance, a deliverance which has already passed and shall not come. For My hand is removed and My spirit taken. For only those in whom I see of Myself shall escape, and only those caught in My embrace shall fly away. Thus as you were made to wait, so shall these within the churches of men wait. For they wait for a sound they no longer recognize, for a call to which they have shut their ears, for a shout from Him whom they have not known, a voice they have altogether rejected. For how can one who rejects My voice heed the call? And how can one who turns away from Me, embrace Me when the shout is made? For they have surely joined themselves to another, they embrace another messiah, a false christ, who looks nothing like Me. Therefore they shall surely pass through the fire, for by no other means shall they be saved."},{"t":"fn","v":"1"}]},{"type":"poetry","lines":[[{"t":"italic","v":"This then is what I command you, little flock:"}],[{"t":"italic","v":"Have compassion, and pray for your brothers and sisters"}],[{"t":"italic","v":"In the churches of men and for the unbelieving of Israel;"}],[{"t":"italic","v":"For they must endure much for the sake of My name..."}]]},{"type":"poetry","lines":[[{"t":"italic","v":"And though the day has passed, lo it has ceased"}],[{"t":"italic","v":"For many, it has not altogether passed away..."}]]},{"type":"poetry","lines":[[{"t":"italic","v":"For My spirit remains with the first election,"}],[{"t":"italic","v":"And shall be restored to the penitent after..."}]]},{"type":"closing","text":"Says The Lord."}],"footnotes":{"1":{"type":"scripture","ref":"1 Corinthians 3:11 (HNV)"}},"nkjv":{"1 Corinthians 3:11 (HNV)":"For no one can lay any other foundation than that which has been laid, which is Yeshua the Messiah."},"audioUrl":"https://thevolumesoftruth.bandcamp.com/track/pentecost-3","videoVoiceUrl":"https://www.youtube.com/watch?v=QRVuknMEXRg&list=PLE8FlkxQPQkPq8VQsKdAQxdkiIuP0i4Fb&index=10","videoMusicUrl":"https://www.youtube.com/user/trumpetcallofgod","relatedTopics":[{"label":"Regarding The Holy Days of God","url":"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"},{"label":"Regarding The Holy Spirit","url":"https://answersonlygodcangive.com/Regarding_The_Holy_Spirit"}],"prevEntry":{"id":"i-shall-remove-my-hand-and-my-spirit-shall-be-withdrawn-and-that-purposed-from-the-beginning-shall-be-done-it-shall-be-accomplished-swiftly","title":"I Shall Remove My Hand and My Spirit Shall Be Withdrawn... And That Purposed from the Beginning Shall Be Done, It Shall Be Accomplished Swiftly"},"nextEntry":{"id":"to-be-set-apart","title":"To Be Set Apart"}},{"id":"to-be-set-apart","num":14,"title":"To Be Set Apart","type":"letter","sourceLabel":"Letters to The Lord's Little Flock","date":"9/7/10","from":"From The Lord, Our God and Savior","spoken":"The Word of The Lord Spoken to Timothy","forLine":"For The Lord’s Little Flock, and For All Those Who Have Ears to Hear","blocks":[{"type":"para","segments":[{"t":"bold-italic","v":"Thus says The Lord to His servants:"},{"t":"text","v":"Beloved ones, hear My words. For I have indeed set you apart to do My will. Therefore you shall honor and celebrate this feast in My name. You shall do all I command you, even that which the world and other believers do not yet understand. This night, you shall blow the trumpet as the sun dips below the horizon, doing so with great sorrow in your hearts, because of that which this world has chosen in all their forsaking of Me; even as a lamentation over all this wickedness mankind has wrought in the earth, which shall come to a swift end at the setting of the sun upon this age of men. Then when morning comes, you shall once again sound the trumpet as the sun breaks the horizon, doing so with great joy in your hearts..."},{"t":"italic","v":"For My Kingdom comes!"}]}],"footnotes":{},"nkjv":{},"audioUrl":"https://thevolumesoftruth.bandcamp.com/track/to-be-set-apart","videoVoiceUrl":"https://www.youtube.com/watch?v=hcb2Klosbpw&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=29","videoMusicUrl":"https://www.youtube.com/user/trumpetcallofgod","relatedTopics":[{"label":"Regarding The Holy Days of God","url":"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"}],"prevEntry":{"id":"pentecost","title":"Pentecost"},"nextEntry":{"id":"atonement","title":"Atonement"}},{"id":"atonement","num":15,"title":"Atonement","type":"letter","sourceLabel":"Letters from Timothy","date":"","from":"","spoken":"","forLine":"","blocks":[{"type":"para","segments":[{"t":"italic","v":"2010 Wisdom Given to Timothy For The Lord’s Little Flock, and For All Those Who Have Ears to Hear (Regarding The Day of Atonement)"}]},{"type":"para","segments":[{"t":"text","v":"Let this day be an offering of abstinence in purity to The Lord, a giving of thanks for your sins atoned for by The Messiah YahuShua; not atonement for your sins, of yourselves, but a free will offering in the name of The Lord your God and Him crucified, rejoicing in the anticipation of The Blessed Hope. And behold, He shall sit upon the throne of His glory and judge the nations. He shall utterly destroy all wickedness from this world, wiping away all that is sin and that which has led His people astray."}]},{"type":"poetry","lines":[[{"t":"italic","v":"And that which was shut shall be opened,"}],[{"t":"italic","v":"And that which was open shall be shut in that Day,"}],[{"t":"italic","v":"Says The Lord."}]]}],"footnotes":{},"nkjv":{},"audioUrl":"https://thevolumesoftruth.bandcamp.com/track/atonement","soundcloudUrl":"https://soundcloud.com/the-volumes-of-truth/atonement?in=the-volumes-of-truth/sets/letters-from-timothy","videoVoiceUrl":"https://www.youtube.com/watch?v=W5M1VWf_sVc&list=PLE8FlkxQPQkO1p9OJVb6bB-BEqydSy3r2&index=6","videoMusicUrl":"https://www.youtube.com/user/trumpetcallofgod","relatedTopics":[{"label":"Regarding The Holy Days of God","url":"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"}],"prevEntry":{"id":"to-be-set-apart","title":"To Be Set Apart"},"nextEntry":{"id":"the-feasts-of-the-lord","title":"The Feasts of The Lord"}},{"id":"the-feasts-of-the-lord","num":16,"title":"The Feasts of The Lord","type":"wtlb","sourceLabel":"Words To Live By: Part One","paragraphs":[{"align":"justify","text":"In these Seven is wisdom and understanding, the very mind of God. For the Holy Days are revelation, revealing hidden things kept secret since the world began - signposts of things to come, a foretaste of The Kingdom, a glimpse into the Glory of God even as the Scriptures, unfolding and coming to light as the will of God is manifest, says The Lord."},{"align":"center","text":"Behold, four are fulfilled:\n\nSalvation assured, sin and death overcome, the Spirit given.\n\n\n\nThree are coming quickly:\n\nSin destroyed, evil bound, My seat taken, Judgment...\n\n\n\nA new day, even one thousand years...\n\n\n\nThen a short season, Consummation...\n\n\n\nAn everlasting day in The Lord!"}],"prevEntry":{"id":"atonement","title":"Atonement"},"scriptures":{}}];
var HOLY_DAYS_META = {"audioPlaylist":"https://thevolumesoftruth.bandcamp.com/album/the-holy-days","videoPlaylist":"https://www.youtube.com/playlist?list=PLSVchFJ22QYKKfZ5cAnLm_TxWABElLw7Z"};
